import React, { useState } from 'react';
import { Button, Select, Input, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { OpeningBalanceDto } from '../../../services/kt/models';
import { yearOptions } from '../../../constants/voucher';
import { formatVnd } from '../../../utils/formatters';
import erp from '../../../styles/erpPage.module.css';

const SoDuDauKyPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningBalanceDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const load = () => {
    setLoading(true);
    ktService.getOpeningBalances(Number(year))
      .then(setItems)
      .catch(err => dispatch(addToast({ message: err?.message ?? 'Lỗi tải số dư', type: 'error' })))
      .finally(() => setLoading(false));
  };

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [year]);

  const updateItem = (idx: number, field: 'debitBalance' | 'creditBalance', val: number) => {
    setItems(prev => prev.map((it, i) => i === idx ? { ...it, [field]: val } : it));
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await ktService.saveOpeningBalances({ year: Number(year), items });
      dispatch(addToast({ message: 'Lưu số dư đầu kỳ thành công', type: 'success' }));
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi lưu', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-balance-scale" /> Số dư đầu kỳ</h1></div>
        <div className={erp.headerActions}>
          <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} size="small" />
          <Button variant="primary" onClick={handleSave} loading={saving}>Lưu</Button>
        </div>
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>TK</th><th>Tên TK</th><th>Đối tượng</th><th className={erp.colRight}>Dư Nợ</th><th className={erp.colRight}>Dư Có</th></tr></thead>
              <tbody>{items.map((it, idx) => (
                <tr key={`${it.accountCode}-${it.customerId ?? idx}`}>
                  <td><code>{it.accountCode}</code></td>
                  <td>{it.accountName}</td>
                  <td>{it.customerName ?? '—'}</td>
                  <td><Input type="number" min={0} value={String(it.debitBalance)} onChange={e => updateItem(idx, 'debitBalance', Number(e.target.value))} /></td>
                  <td><Input type="number" min={0} value={String(it.creditBalance)} onChange={e => updateItem(idx, 'creditBalance', Number(e.target.value))} /></td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoDuDauKyPage;
